import React, { useState, useEffect } from 'react';
import { Users, Building2, TrendingUp, Activity } from 'lucide-react';
import { getDashboardData } from '../services/api';
import { format } from 'date-fns';

const StatCard = ({ title, value, icon: Icon, color, change }) => (
  <div className="card">
    <div className="flex items-center justify-between">
      <div>
        <p className="text-sm font-medium text-gray-600">{title}</p>
        <p className="text-2xl font-bold text-gray-900 mt-2">{value}</p>
        {change && (
          <p className={`text-sm mt-2 ${change >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            {change >= 0 ? '+' : ''}{change}% from last month
          </p>
        )}
      </div>
      <div className={`p-3 rounded-lg ${color}`}>
        <Icon className="h-6 w-6 text-white" />
      </div>
    </div>
  </div>
);

const RecentActivity = ({ title, items, type }) => {
  const getTypeColor = (active) => active ? 'status-active' : 'status-inactive';

  return (
    <div className="card">
      <h3 className="text-lg font-semibold text-gray-900 mb-4">{title}</h3>
      <div className="space-y-3">
        {items?.slice(0, 5).map((item) => (
          <div key={item.id} className="flex items-center justify-between py-2">
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-900">
                {type === 'student' ? item.fullName : item.companyName}
              </p>
              <p className="text-xs text-gray-500">
                {type === 'student' ? item.email : item.industry}
              </p>
            </div>
            <div className="text-right">
              <span className={`status-badge ${getTypeColor(item.active)}`}>
                {item.active ? 'Active' : 'Inactive'}
              </span>
              <p className="text-xs text-gray-500 mt-1">
                {format(new Date(item.registrationDate), 'MMM dd, yyyy')}
              </p>
            </div>
          </div>
        ))}
        {(!items || items.length === 0) && (
          <p className="text-gray-500 text-center py-4">No recent {type}s</p>
        )}
      </div>
    </div>
  );
};

const Dashboard = () => {
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        const response = await getDashboardData();
        setDashboardData(response.data);
      } catch (err) {
        setError('Failed to load dashboard data');
        console.error('Dashboard error:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-12">
        <div className="text-red-600 text-lg font-medium">{error}</div>
        <button 
          onClick={() => window.location.reload()} 
          className="mt-4 btn-primary"
        >
          Try Again
        </button>
      </div>
    );
  }

  const stats = [
    {
      title: 'Total Students',
      value: dashboardData?.totalStudents || 0,
      icon: Users,
      color: 'bg-blue-500',
      change: 12
    },
    {
      title: 'Active Students',
      value: dashboardData?.activeStudents || 0,
      icon: Activity,
      color: 'bg-green-500',
      change: 8
    },
    {
      title: 'Total Companies',
      value: dashboardData?.totalCompanies || 0,
      icon: Building2,
      color: 'bg-purple-500',
      change: 15
    },
    {
      title: 'Active Companies',
      value: dashboardData?.activeCompanies || 0,
      icon: TrendingUp,
      color: 'bg-orange-500',
      change: 10
    }
  ];

  return (
    <div>
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600 mt-2">Welcome to the placement admin panel</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {stats.map((stat, index) => (
          <StatCard key={index} {...stat} />
        ))}
      </div>

      {/* Recent Activity */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <RecentActivity 
          title="Recent Students" 
          items={dashboardData?.recentStudents}
          type="student"
        />
        <RecentActivity 
          title="Recent Companies" 
          items={dashboardData?.recentCompanies}
          type="company"
        />
      </div>
    </div>
  );
};

export default Dashboard;
